@* Manages wizard step navigation and owns the Order state. *@

@if (currentStep == Step.Shipping)
{
    <ShippingStep Shipping="order.Shipping"
                  OnNext="HandleShippingNext" />
}
else
{
    <PaymentStep Payment="order.Payment"
                 OnBack="HandleBack"
                 OnPlaceOrder="HandlePlaceOrder" />
}

@code {
    [Parameter] public EventCallback<Order> OnOrderPlaced { get; set; }

    private enum Step { Shipping, Payment }

    private Step currentStep = Step.Shipping;
    private Order order = new();

    private Task HandleShippingNext(ShippingInfo shipping)
    {
        order.Shipping = shipping;
        currentStep = Step.Payment;
        return Task.CompletedTask;
    }

    private Task HandleBack()
    {
        currentStep = Step.Shipping;
        return Task.CompletedTask;
    }

    private Task HandlePlaceOrder(PaymentInfo payment)
    {
        order.Payment = payment;
        return OnOrderPlaced.InvokeAsync(order);
    }
}

