    private ShippingInfo shipping = new();
    private string? validationMessage;

    protected override void OnParametersSet()
    {
        shipping = new ShippingInfo
        {
            Name = Shipping.Name,
            Address = Shipping.Address,
            City = Shipping.City,
            ZipCode = Shipping.ZipCode
        };
    }

    private Task HandleNext()
    {
        if (string.IsNullOrWhiteSpace(shipping.Name) || string.IsNullOrWhiteSpace(shipping.Address))
        {
            validationMessage = "Name and Address are required.";
            return Task.CompletedTask;
        }

        validationMessage = null;
        return OnNext.InvokeAsync(shipping);
    }
}
